var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"INSPECTOR_NPC_NULL_A","text":{"KOREA":"퇴각! 퇴각하라!","JPN":"退却！　退却しろ！","ENG":"Fall back! Retreat!","TWN":"撤退！撤退！"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"INSPECTOR_NPC_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INSPECTOR_NPC_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"INSPECTOR_NPC_NULL_B","text":{"KOREA":"제기랄! 뭐야, 저 벼락은! 아까부터 전혀 약해지질 않아!","JPN":"くそ！　何だ、あの雷は！　さっきから全然弱まらねえ！","ENG":"Dammit! What the hell is that?! The lightning isn’t getting any weaker!","TWN":"該死！怎麼會有電！而且都沒有變弱的趨勢！"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"INSPECTOR_NPC_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INSPECTOR_NPC_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"INSPECTOR_NPC_NULL_B","text":{"KOREA":"장비는 모두 버려! 살아남는 게 우선이다!","JPN":"装備はすべて捨てろ！　生き残るのが先だ！","ENG":"Leave the gear! Our priority is getting out of here alive!","TWN":"裝備全都扔掉！現在保命要緊！"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"INSPECTOR_NPC_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INSPECTOR_NPC_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"대령님, 몸은 괜찮으십니까?","JPN":"大佐、お体は大丈夫ですか？","ENG":"Colonel! Are you okay?","TWN":"上校，您的身體沒問題嗎？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"문제없어. 저런 약골들 상대쯤이야.","JPN":"問題ない。あんな軟弱な奴らくらい。","ENG":"I’m fine. Those weaklings won’t be able to put a scratch on me.","TWN":"沒問題，對付那些弱不禁風的傢伙還行。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"다행입니다. 스톰 브링거를 사용할 수 없다고 해서 우려했습니다만.","JPN":"それはよかったです。ストームブリンガーを使えないというから心配しましたが。","ENG":"That’s a relief, sir. I was concerned when I heard that Stormbringer couldn’t be used.","TWN":"那就好，我聽說不能使用興風者，原本還有點擔心呢。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"카일, 그런 거창한 건 적어도 신을 상대할 때나 쓰는 거야.","JPN":"カイル、そんな大物は少なくとも神相手に使うもんだ。","ENG":"Kyle, something that massive would only be used against a god.","TWN":"凱爾，殺雞焉用牛刀，"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"저런 녀석들 상대로는 반칙이라고.","JPN":"あんな奴らには反則だぞ。","ENG":"It would be cheating to use that against small fry like them.","TWN":"這樣對他們是不公平的！"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"INSPECTOR_NPC_NULL_CHIEF","text":{"KOREA":"큭……! 저 건방진 자식……!","JPN":"くっ……！　生意気な……！","ENG":"Grr...! That arrogant kid...!","TWN":"咳……！囂張的傢伙……！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"INSPECTOR_NPC_NULL_CHIEF","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"INSPECTOR_NPC_NULL_NULL","text":{"KOREA":"대장님, 카운터 없이 적의 정예 전력까지 상대하는 것은 불가능합니다.","JPN":"隊長、カウンターなしで敵の精鋭戦力まで相手することはできません。","ENG":"Chief, without any Counters, it’d be impossible to fight the enemy’s elite forces.","TWN":"組長，在沒有制裁者的情況下，我們根本打不過對方。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"INSPECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"INSPECTOR_NPC_NULL_NULL","text":{"KOREA":"지금 퇴각하지 않으면──","JPN":"今退却しないと――","ENG":"If we don’t retreat now─","TWN":"再不撤退的話──"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"INSPECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"INSPECTOR_NPC_NULL_CHIEF","text":{"KOREA":"말도 안 되는 소리…… 여기서 물러나라고?","JPN":"バカ言うな……ここで引っ込めと？","ENG":"Don’t be absurd! Retreat at this stage of our plans?!","TWN":"胡說什麼……現在撤退？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"INSPECTOR_NPC_NULL_CHIEF","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"INSPECTOR_NPC_NULL_CHIEF","text":{"KOREA":"그래선 안 되지. 그래선 안 되고 말고……!","JPN":"そうはできない。できないとも……！","ENG":"We can’t do that, not like this...!","TWN":"這怎麼行？不能退……！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"INSPECTOR_NPC_NULL_CHIEF","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"흐음, 무슨 일 때문에 전용 회선으로 연락했습니까?","JPN":"ふむ、どういった用件で専用回線から連絡されたのですかな？","ENG":"Hmm... I hope there is a good reason that you called my personal line.","TWN":"嗯，打這支專屬電話是有什麼事？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"INSPECTOR_NPC_NULL_CHIEF","text":{"KOREA":"며, 면목 없습니다. 고고학부장님.","JPN":"め、面目ございません。考古学部長。","ENG":"M-my apologies, Dean of Archeology.","TWN":"我…我沒臉見您，考古學教授。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"INSPECTOR_NPC_NULL_CHIEF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};